#include <math.h>
#include <SD.h>
#define STRAIN_PIN A0
#define SOL_PIN 6
#define BUZZER 8
#define LED 9
#define SD_CS 10
#define GAIN 500.0f
#define GF 2.1f
#define A_M2 6.56e-3f
#define E_GPA 200.0f
#define I_CM4 5210.0f
#define L_M 3.5f
#define K_EFF 0.7f
#define DT 0.1f
float intg=0,lastE=0;

float euler_critical_load(float E,float I,float L,float K){
  float Ef=E*1e6f,If=I*1e-8f,KL=K*L;
  return PI*PI*Ef*If/(KL*KL)/1000.0f;
}

float read_load_kN(){
  float V=(analogRead(STRAIN_PIN)/1023.0f)*5.0f;
  float eps=(V/(GAIN*5.0f))*2.0f/GF;
  return eps*(E_GPA*1e9f)*A_M2/1000.0f;
}

void run_pid_shore(float frac){
  float sp=0.75f,e=frac-sp;
  intg+=e*DT; intg=constrain(intg,-1,1);
  float d=(e-lastE)/DT; lastE=e;
  int duty=(int)constrain((80.0f*e+30.0f*intg+5.0f*d)*255,0,255);
  analogWrite(SOL_PIN,duty);
}

void run_alarm(float frac){
  if(frac>=0.95f){tone(BUZZER,2000);analogWrite(LED,255);}
  else if(frac>=0.80f){tone(BUZZER,1000);analogWrite(LED,128);}
  else{noTone(BUZZER);analogWrite(LED,0);}
}

void log_sd(float load,float pcr){
  File f=SD.open("column.csv",FILE_WRITE);
  if(f){f.print(millis());f.print(',');f.print(load);f.print(',');f.println(pcr);f.close();}
}

void setup(){Serial.begin(115200);pinMode(SOL_PIN,OUTPUT);pinMode(BUZZER,OUTPUT);pinMode(LED,OUTPUT);SD.begin(SD_CS);}

void loop(){
  float load=read_load_kN();
  float pcr=euler_critical_load(E_GPA,I_CM4,L_M,K_EFF);
  float frac=load/pcr;
  run_pid_shore(frac);
  run_alarm(frac);
  log_sd(load,pcr);
  Serial.print("f=");Serial.println(frac);
  delay(100);
}
